    35→	"k8s.io/klog/v2"
    36→	"k8s.io/kubernetes/pkg/features"
    37→	kubecontainer "k8s.io/kubernetes/pkg/kubelet/container"
    38→	"k8s.io/kubernetes/pkg/kubelet/metrics"
    39→	kubetypes "k8s.io/kubernetes/pkg/kubelet/types"
    40→	"k8s.io/kubernetes/pkg/kubelet/util/format"
    41→	httpprobe "k8s.io/kubernetes/pkg/probe/http"
    42→	"k8s.io/kubernetes/pkg/security/apparmor"
    43→)
    44→
    45→const (
    46→	maxRespBodyLength = 10 * 1 << 10 // 10KB
    47→
    48→	AppArmorNotAdmittedReason = "AppArmor"
    49→)
    50→
    51→type handlerRunner struct {
    52→	httpDoer         kubetypes.HTTPDoer
    53→	commandRunner    kubecontainer.CommandRunner
    54→	containerManager podStatusProvider
    55→	eventRecorder    record.EventRecorder
    56→}
    57→
    58→type podStatusProvider interface {
    59→	GetPodStatus(ctx context.Context, uid types.UID, name, namespace string) (*kubecontainer.PodStatus, error)
    60→}
    61→
    62→// NewHandlerRunner returns a configured lifecycle handler for a container.
    63→func NewHandlerRunner(httpDoer kubetypes.HTTPDoer, commandRunner kubecontainer.CommandRunner, containerManager podStatusProvider, eventRecorder record.EventRecorder) kubecontainer.HandlerRunner {
    64→	return &handlerRunner{
    65→		httpDoer:         httpDoer,
    66→		commandRunner:    commandRunner,
    67→		containerManager: containerManager,
    68→		eventRecorder:    eventRecorder,
    69→	}
    70→}
    71→
    72→func (hr *handlerRunner) Run(ctx context.Context, containerID kubecontainer.ContainerID, pod *v1.Pod, container *v1.Container, handler *v1.LifecycleHandler) (string, error) {
    73→	switch {
    74→	case handler.Exec != nil:
    75→		var msg string
    76→		// TODO(tallclair): Pass a proper timeout value.
    77→		output, err := hr.commandRunner.RunInContainer(ctx, containerID, handler.Exec.Command, 0)
    78→		if err != nil {
    79→			msg = fmt.Sprintf("Exec lifecycle hook (%v) for Container %q in Pod %q failed - error: %v, message: %q", handler.Exec.Command, container.Name, format.Pod(pod), err, string(output))
    80→			klog.V(1).ErrorS(err, "Exec lifecycle hook for Container in Pod failed", "execCommand", handler.Exec.Command, "containerName", container.Name, "pod", klog.KObj(pod), "message", string(output))
    81→		}
    82→		return msg, err
    83→	case handler.HTTPGet != nil:
    84→		err := hr.runHTTPHandler(ctx, pod, container, handler, hr.eventRecorder)
    85→		var msg string
    86→		if err != nil {
    87→			msg = fmt.Sprintf("HTTP lifecycle hook (%s) for Container %q in Pod %q failed - error: %v", handler.HTTPGet.Path, container.Name, format.Pod(pod), err)
    88→			klog.V(1).ErrorS(err, "HTTP lifecycle hook for Container in Pod failed", "path", handler.HTTPGet.Path, "containerName", container.Name, "pod", klog.KObj(pod))
    89→		}
    90→		return msg, err
    91→	case handler.Sleep != nil:
    92→		err := hr.runSleepHandler(ctx, handler.Sleep.Seconds)
    93→		var msg string
    94→		if err != nil {
    95→			msg = fmt.Sprintf("Sleep lifecycle hook (%d) for Container %q in Pod %q failed - error: %v", handler.Sleep.Seconds, container.Name, format.Pod(pod), err)
    96→			klog.V(1).ErrorS(err, "Sleep lifecycle hook for Container in Pod failed", "sleepSeconds", handler.Sleep.Seconds, "containerName", container.Name, "pod", klog.KObj(pod))
    97→		}
    98→		return msg, err
    99→	default:
   100→		err := fmt.Errorf("invalid handler: %v", handler)
   101→		msg := fmt.Sprintf("Cannot run handler: %v", err)
   102→		klog.ErrorS(err, "Cannot run handler")
   103→		return msg, err
   104→	}
   105→}
   106→
   107→// resolvePort attempts to turn an IntOrString port reference into a concrete port number.
   108→// If portReference has an int value, it is treated as a literal, and simply returns that value.
   109→// If portReference is a string, an attempt is first made to parse it as an integer.  If that fails,
   110→// an attempt is made to find a port with the same name in the container spec.
   111→// If a port with the same name is found, it's ContainerPort value is returned.  If no matching
   112→// port is found, an error is returned.
   113→func resolvePort(portReference intstr.IntOrString, container *v1.Container) (int, error) {
   114→	if portReference.Type == intstr.Int {
   115→		return portReference.IntValue(), nil
   116→	}
   117→	portName := portReference.StrVal
   118→	port, err := strconv.Atoi(portName)
   119→	if err == nil {
   120→		return port, nil
   121→	}
   122→	for _, portSpec := range container.Ports {
   123→		if portSpec.Name == portName {
   124→			return int(portSpec.ContainerPort), nil
   125→		}
   126→	}
   127→	return -1, fmt.Errorf("couldn't find port: %v in %v", portReference, container)
   128→}
   129→
   130→func (hr *handlerRunner) runSleepHandler(ctx context.Context, seconds int64) error {
   131→	if !utilfeature.DefaultFeatureGate.Enabled(features.PodLifecycleSleepAction) {
   132→		return nil
   133→	}
   134→	c := time.After(time.Duration(seconds) * time.Second)
   135→	select {
   136→	case <-ctx.Done():
   137→		// unexpected termination
   138→		metrics.LifecycleHandlerSleepTerminated.Inc()
   139→		return fmt.Errorf("container terminated before sleep hook finished")
   140→	case <-c:
   141→		return nil
   142→	}
   143→}
   144→
   145→func (hr *handlerRunner) runHTTPHandler(ctx context.Context, pod *v1.Pod, container *v1.Container, handler *v1.LifecycleHandler, eventRecorder record.EventRecorder) error {
   146→	host := handler.HTTPGet.Host
   147→	podIP := host
   148→	if len(host) == 0 {
   149→		status, err := hr.containerManager.GetPodStatus(ctx, pod.UID, pod.Name, pod.Namespace)
   150→		if err != nil {
   151→			klog.ErrorS(err, "Unable to get pod info, event handlers may be invalid.", "pod", klog.KObj(pod))
   152→			return err
   153→		}
   154→		if len(status.IPs) == 0 {
   155→			return fmt.Errorf("failed to find networking container: %v", status)
   156→		}
   157→		host = status.IPs[0]
   158→		podIP = host
   159→	}
   160→
   161→	req, err := httpprobe.NewRequestForHTTPGetAction(handler.HTTPGet, container, podIP, "lifecycle")
   162→	if err != nil {
   163→		return err
   164→	}
   165→	resp, err := hr.httpDoer.Do(req)
   166→	discardHTTPRespBody(resp)
   167→
   168→	if isHTTPResponseError(err) {
   169→		klog.V(1).ErrorS(err, "HTTPS request to lifecycle hook got HTTP response, retrying with HTTP.", "pod", klog.KObj(pod), "host", req.URL.Host)
   170→
   171→		req := req.Clone(context.Background())
   172→		req.URL.Scheme = "http"
   173→		req.Header.Del("Authorization")
   174→		resp, httpErr := hr.httpDoer.Do(req)
   175→
   176→		// clear err since the fallback succeeded
   177→		if httpErr == nil {
   178→			metrics.LifecycleHandlerHTTPFallbacks.Inc()
   179→			if eventRecorder != nil {
   180→				// report the fallback with an event
   181→				eventRecorder.Event(pod, v1.EventTypeWarning, "LifecycleHTTPFallback", fmt.Sprintf("request to HTTPS lifecycle hook %s got HTTP response, retry with HTTP succeeded", req.URL.Host))
   182→			}
   183→			err = nil
   184→		}
   185→		discardHTTPRespBody(resp)
   186→	}
   187→	return err
   188→}
   189→
   190→func discardHTTPRespBody(resp *http.Response) {
   191→	if resp == nil {
   192→		return
   193→	}
   194→
   195→	// Ensure the response body is fully read and closed
   196→	// before we reconnect, so that we reuse the same TCP
   197→	// connection.
   198→	defer resp.Body.Close()
   199→
   200→	if resp.ContentLength <= maxRespBodyLength {
   201→		io.Copy(io.Discard, &io.LimitedReader{R: resp.Body, N: maxRespBodyLength})
   202→	}
   203→}
   204→
   205→// NewAppArmorAdmitHandler returns a PodAdmitHandler which is used to evaluate
   206→// if a pod can be admitted from the perspective of AppArmor.
   207→func NewAppArmorAdmitHandler(validator apparmor.Validator) PodAdmitHandler {
   208→	return &appArmorAdmitHandler{
   209→		Validator: validator,
   210→	}
   211→}
   212→
   213→type appArmorAdmitHandler struct {
   214→	apparmor.Validator
   215→}
   216→
   217→func (a *appArmorAdmitHandler) Admit(attrs *PodAdmitAttributes) PodAdmitResult {
   218→	// If the pod is already running or terminated, no need to recheck AppArmor.
   219→	if attrs.Pod.Status.Phase != v1.PodPending {
   220→		return PodAdmitResult{Admit: true}
   221→	}
   222→
   223→	err := a.Validate(attrs.Pod)
   224→	if err == nil {
   225→		return PodAdmitResult{Admit: true}
   226→	}
   227→	return PodAdmitResult{
   228→		Admit:   false,
   229→		Reason:  AppArmorNotAdmittedReason,
   230→		Message: fmt.Sprintf("Cannot enforce AppArmor: %v", err),
   231→	}
   232→}
   233→
   234→func isHTTPResponseError(err error) bool {
   235→	if err == nil {
   236→		return false
   237→	}
   238→	urlErr := &url.Error{}
   239→	if !errors.As(err, &urlErr) {
   240→		return false
   241→	}
   242→	return strings.Contains(urlErr.Err.Error(), "server gave HTTP response to HTTPS client")
   243→}
