100→// NewPredicateAdmitHandler returns a PodAdmitHandler which is used to evaluates
   101→// if a pod can be admitted from the perspective of predicates.
   102→func NewPredicateAdmitHandler(getNodeAnyWayFunc getNodeAnyWayFuncType, admissionFailureHandler AdmissionFailureHandler, pluginResourceUpdateFunc pluginResourceUpdateFuncType) PodAdmitHandler {
   103→	return &predicateAdmitHandler{
   104→		getNodeAnyWayFunc,
   105→		pluginResourceUpdateFunc,
   106→		admissionFailureHandler,
   107→	}
   108→}
   109→
   110→func (w *predicateAdmitHandler) Admit(attrs *PodAdmitAttributes) PodAdmitResult {
   111→	node, err := w.getNodeAnyWayFunc()
   112→	if err != nil {
   113→		klog.ErrorS(err, "Cannot get Node info")
   114→		return PodAdmitResult{
   115→			Admit:   false,
   116→			Reason:  InvalidNodeInfo,
   117→			Message: "Kubelet cannot get node info.",
   118→		}
   119→	}
   120→	admitPod := attrs.Pod
   121→
   122→	// perform the checks that preemption will not help first to avoid meaningless pod eviction
   123→	if rejectPodAdmissionBasedOnOSSelector(admitPod, node) {
   124→		return PodAdmitResult{
   125→			Admit:   false,
   126→			Reason:  PodOSSelectorNodeLabelDoesNotMatch,
   127→			Message: "Failed to admit pod as the `kubernetes.io/os` label doesn't match node label",
   128→		}
   129→	}
   130→	if rejectPodAdmissionBasedOnOSField(admitPod) {
   131→		return PodAdmitResult{
   132→			Admit:   false,
   133→			Reason:  PodOSNotSupported,
   134→			Message: "Failed to admit pod as the OS field doesn't match node OS",
   135→		}
   136→	}
   137→
   138→	pods := attrs.OtherPods
   139→	nodeInfo := schedulerframework.NewNodeInfo(pods...)
   140→	nodeInfo.SetNode(node)
   141→
   142→	// TODO: Remove this after the SidecarContainers feature gate graduates to GA.
   143→	if !utilfeature.DefaultFeatureGate.Enabled(features.SidecarContainers) {
   144→		for _, c := range admitPod.Spec.InitContainers {
   145→			if podutil.IsRestartableInitContainer(&c) {
   146→				message := fmt.Sprintf("Init container %q may not have a non-default restartPolicy", c.Name)
   147→				klog.InfoS("Failed to admit pod", "pod", klog.KObj(admitPod), "message", message)
   148→				return PodAdmitResult{
   149→					Admit:   false,
   150→					Reason:  InitContainerRestartPolicyForbidden,
   151→					Message: message,
   152→				}
   153→			}
   154→		}
   155→	}
   156→
   157→	// ensure the node has enough plugin resources for that required in pods
   158→	if err = w.pluginResourceUpdateFunc(nodeInfo, attrs); err != nil {
   159→		message := fmt.Sprintf("Update plugin resources failed due to %v, which is unexpected.", err)
   160→		klog.InfoS("Failed to admit pod", "pod", klog.KObj(admitPod), "message", message)
   161→		return PodAdmitResult{
   162→			Admit:   false,
   163→			Reason:  UnexpectedAdmissionError,
   164→			Message: message,
   165→		}
   166→	}
   167→
   168→	// Remove the requests of the extended resources that are missing in the
   169→	// node info. This is required to support cluster-level resources, which
   170→	// are extended resources unknown to nodes.
   171→	//
   172→	// Caveat: If a pod was manually bound to a node (e.g., static pod) where a
   173→	// node-level extended resource it requires is not found, then kubelet will
   174→	// not fail admission while it should. This issue will be addressed with
   175→	// the Resource Class API in the future.
   176→	podWithoutMissingExtendedResources := removeMissingExtendedResources(admitPod, nodeInfo)
   177→
   178→	reasons := generalFilter(podWithoutMissingExtendedResources, nodeInfo)
   179→	fit := len(reasons) == 0
   180→	if !fit {
   181→		reasons, err = w.admissionFailureHandler.HandleAdmissionFailure(admitPod, reasons)
   182→		fit = len(reasons) == 0 && err == nil
   183→		if err != nil {
   184→			message := fmt.Sprintf("Unexpected error while attempting to recover from admission failure: %v", err)
   185→			klog.InfoS("Failed to admit pod, unexpected error while attempting to recover from admission failure", "pod", klog.KObj(admitPod), "err", err)
   186→			return PodAdmitResult{
   187→				Admit:   fit,
   188→				Reason:  UnexpectedAdmissionError,
   189→				Message: message,
   190→			}
   191→		}
   192→	}
   193→	if !fit {
   194→		var reason string
   195→		var message string
   196→		if len(reasons) == 0 {
   197→			message = fmt.Sprint("GeneralPredicates failed due to unknown reason, which is unexpected.")
